import { useEffect } from 'react';
import { ReactFlowProvider } from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import { PlanCanvas } from './components/Canvas/PlanCanvas';
import { Header } from './components/Layout/Header';
import { Footer } from './components/Layout/Footer';
import { NodeDetailPanel } from './components/Panel/NodeDetailPanel';
import { ApproveButton } from './components/Controls/ApproveButton';
import { InsertNodeModal } from './components/Modals/InsertNodeModal';
import { usePlanStore } from './stores/plan-store';
import { useWebSocket } from './hooks/useWebSocket';

function App() {
  const { selectedNodeId, plan, canApprove } = usePlanStore();
  const { approvePlan, pauseExecution, resumeExecution } = useWebSocket();

  // Keyboard shortcuts
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Enter to approve
      if (e.key === 'Enter' && plan?.status === 'ready' && canApprove()) {
        e.preventDefault();
        approvePlan();
      }
      // Escape to deselect
      if (e.key === 'Escape') {
        usePlanStore.getState().setSelectedNodeId(null);
      }
      // Space to pause/resume (only when not typing in an input)
      if (e.key === ' ' && (plan?.status === 'executing' || plan?.status === 'paused')) {
        const target = e.target as HTMLElement;
        if (target.tagName !== 'INPUT' && target.tagName !== 'TEXTAREA') {
          e.preventDefault();
          if (plan?.status === 'paused') {
            resumeExecution();
          } else {
            pauseExecution();
          }
        }
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [plan, canApprove, approvePlan, pauseExecution, resumeExecution]);

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden bg-canvas">
      <Header />

      <main className="flex-1 relative">
        <ReactFlowProvider>
          <PlanCanvas />
        </ReactFlowProvider>

        {/* Approve button - shown when plan is ready */}
        <ApproveButton />

        {/* Side panel for node details */}
        {selectedNodeId && <NodeDetailPanel />}
      </main>

      <Footer />

      {/* Insert node modal */}
      <InsertNodeModal />
    </div>
  );
}

export default App;
