import { create } from 'zustand';

// Types for our plan data
export type NodeStatus = 'pending' | 'active' | 'completed' | 'failed' | 'skipped';
export type NodeType = 'task' | 'decision';
export type FieldType = 'string' | 'secret' | 'select' | 'boolean' | 'number' | 'file';

export interface DynamicField {
  id: string;
  name: string;
  type: FieldType;
  required: boolean;
  title: string;
  description: string;
  value?: string;
  options?: string; // Comma-separated for select
  setupInstructions?: string;
}

export interface Branch {
  id: string;
  label: string;
  description: string;
  pros?: string;
  cons?: string;
}

export interface FileAttachment {
  id: string;
  path: string;
  name: string;
  type: 'image' | 'code' | 'document' | 'other';
  description: string;
}

export interface McpServer {
  mcpId: string;
  githubUrl: string;
  name: string;
  author: string;
  description: string;
  codiconIcon: string;
  logoUrl: string;
  category: string;
  tags: string[];
  requiresApiKey: boolean;
  readmeContent: string;
  isRecommended: boolean;
  githubStars: number;
  downloadCount: number;
  createdAt: string;
  updatedAt: string;
}

export interface PlanNode {
  id: string;
  type: NodeType;
  status: NodeStatus;
  title: string;
  description: string;
  complexity?: 'low' | 'medium' | 'high';
  expectedOutput?: string;
  risks?: string;
  dynamicFields: DynamicField[];
  branches?: Branch[];
  selectedBranchId?: string;
  branchParent?: string;
  branchId?: string;
  output?: string; // Execution output
  attachments: FileAttachment[]; // User-attached files
  metaInstructions?: string; // User instructions for the LLM
  mcpServer?: McpServer; // Attached MCP server for this node
}

export interface PlanEdge {
  id: string;
  from: string;
  to: string;
}

export interface Plan {
  id: string;
  title: string;
  agent: string;
  prompt?: string;
  createdAt: string;
  status: 'streaming' | 'ready' | 'approved' | 'executing' | 'paused' | 'completed' | 'failed';
}

interface PlanState {
  // Connection state
  isConnected: boolean;
  setConnected: (connected: boolean) => void;

  // Plan metadata
  plan: Plan | null;
  setPlan: (plan: Plan) => void;
  updatePlanStatus: (status: Plan['status']) => void;

  // Nodes and edges
  nodes: PlanNode[];
  edges: PlanEdge[];
  addNode: (node: PlanNode) => void;
  addEdge: (edge: PlanEdge) => void;
  updateNode: (id: string, updates: Partial<PlanNode>) => void;
  updateNodeStatus: (id: string, status: NodeStatus, output?: string) => void;
  setSelectedBranch: (nodeId: string, branchId: string) => void;
  updateFieldValue: (nodeId: string, fieldId: string, value: string) => void;
  addAttachment: (nodeId: string, attachment: FileAttachment) => void;
  removeAttachment: (nodeId: string, attachmentId: string) => void;
  updateMetaInstructions: (nodeId: string, instructions: string) => void;
  setNodeMcpServer: (nodeId: string, mcpServer: McpServer | undefined) => void;

  // UI state
  selectedNodeId: string | null;
  setSelectedNodeId: (id: string | null) => void;

  // Execution progress
  currentNodeId: string | null;
  completedCount: number;
  totalCount: number;

  // Actions
  clearPlan: () => void;
  approvePlan: () => void;
  canApprove: () => boolean;

  // Re-run actions
  requestRerun: (nodeId: string, mode: 'single' | 'to-bottom') => void;
  pendingRerun: { nodeId: string; mode: 'single' | 'to-bottom' } | null;
  clearPendingRerun: () => void;

  // Pause/Resume actions
  pauseExecution: () => void;
  resumeExecution: () => void;

  // Node insertion
  insertNodes: (nodes: PlanNode[], edges: PlanEdge[], removedEdgeIds: string[]) => void;
  pendingInsert: { afterNodeId: string } | null;
  setPendingInsert: (afterNodeId: string | null) => void;

  // Node removal
  removeNode: (nodeId: string) => void;
}

export const usePlanStore = create<PlanState>((set, get) => ({
  // Connection
  isConnected: false,
  setConnected: (connected) => set({ isConnected: connected }),

  // Plan
  plan: null,
  setPlan: (plan) => set({ plan }),
  updatePlanStatus: (status) =>
    set((state) => ({
      plan: state.plan ? { ...state.plan, status } : null,
    })),

  // Nodes & edges
  nodes: [],
  edges: [],

  addNode: (node) =>
    set((state) => ({
      nodes: [...state.nodes, { ...node, attachments: node.attachments || [] }],
      totalCount: state.totalCount + 1,
    })),

  addEdge: (edge) =>
    set((state) => ({
      edges: [...state.edges, edge],
    })),

  updateNode: (id, updates) =>
    set((state) => ({
      nodes: state.nodes.map((n) => (n.id === id ? { ...n, ...updates } : n)),
    })),

  updateNodeStatus: (id, status, output) =>
    set((state) => {
      const newNodes = state.nodes.map((n) =>
        n.id === id ? { ...n, status, output: output ?? n.output } : n
      );
      const completedCount = newNodes.filter((n) => n.status === 'completed').length;
      const currentNodeId = status === 'active' ? id : state.currentNodeId;

      return { nodes: newNodes, completedCount, currentNodeId };
    }),

  setSelectedBranch: (nodeId, branchId) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === nodeId ? { ...n, selectedBranchId: branchId } : n
      ),
    })),

  updateFieldValue: (nodeId, fieldId, value) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === nodeId
          ? {
              ...n,
              dynamicFields: n.dynamicFields.map((f) =>
                f.id === fieldId ? { ...f, value } : f
              ),
            }
          : n
      ),
    })),

  addAttachment: (nodeId, attachment) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === nodeId
          ? { ...n, attachments: [...n.attachments, attachment] }
          : n
      ),
    })),

  removeAttachment: (nodeId, attachmentId) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === nodeId
          ? { ...n, attachments: n.attachments.filter((a) => a.id !== attachmentId) }
          : n
      ),
    })),

  updateMetaInstructions: (nodeId, instructions) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === nodeId ? { ...n, metaInstructions: instructions } : n
      ),
    })),

  setNodeMcpServer: (nodeId, mcpServer) =>
    set((state) => ({
      nodes: state.nodes.map((n) =>
        n.id === nodeId ? { ...n, mcpServer } : n
      ),
    })),

  // UI
  selectedNodeId: null,
  setSelectedNodeId: (id) => set({ selectedNodeId: id }),

  // Execution
  currentNodeId: null,
  completedCount: 0,
  totalCount: 0,

  // Actions
  clearPlan: () =>
    set({
      plan: null,
      nodes: [],
      edges: [],
      selectedNodeId: null,
      currentNodeId: null,
      completedCount: 0,
      totalCount: 0,
    }),

  approvePlan: () =>
    set((state) => ({
      plan: state.plan ? { ...state.plan, status: 'approved' } : null,
    })),

  canApprove: () => {
    const state = get();

    // Check all required fields are filled
    for (const node of state.nodes) {
      for (const field of node.dynamicFields) {
        if (field.required && !field.value) {
          return false;
        }
      }

      // Check decision nodes have a selected branch
      if (node.type === 'decision' && node.branches && !node.selectedBranchId) {
        return false;
      }
    }

    return state.plan?.status === 'ready';
  },

  // Re-run actions
  pendingRerun: null,

  requestRerun: (nodeId, mode) =>
    set({ pendingRerun: { nodeId, mode } }),

  clearPendingRerun: () =>
    set({ pendingRerun: null }),

  // Pause/Resume actions
  pauseExecution: () =>
    set((state) => ({
      plan: state.plan ? { ...state.plan, status: 'paused' } : null,
    })),

  resumeExecution: () =>
    set((state) => ({
      plan: state.plan ? { ...state.plan, status: 'executing' } : null,
    })),

  // Node insertion
  insertNodes: (nodes, edges, removedEdgeIds) =>
    set((state) => ({
      nodes: [...state.nodes, ...nodes],
      edges: [
        ...state.edges.filter(e => !removedEdgeIds.includes(e.id)),
        ...edges,
      ],
      totalCount: state.totalCount + nodes.length,
    })),

  pendingInsert: null,

  setPendingInsert: (afterNodeId) =>
    set({ pendingInsert: afterNodeId ? { afterNodeId } : null }),

  // Node removal - reconnects edges around the removed node
  removeNode: (nodeId) =>
    set((state) => {
      // Find edges connected to this node
      const incomingEdges = state.edges.filter(e => e.to === nodeId);
      const outgoingEdges = state.edges.filter(e => e.from === nodeId);

      // Create new edges to bridge the gap
      const newEdges: PlanEdge[] = [];
      for (const incoming of incomingEdges) {
        for (const outgoing of outgoingEdges) {
          newEdges.push({
            id: `edge_${incoming.from}_${outgoing.to}`,
            from: incoming.from,
            to: outgoing.to,
          });
        }
      }

      // Remove the node and its connected edges, add new bridging edges
      const edgeIdsToRemove = new Set([
        ...incomingEdges.map(e => e.id),
        ...outgoingEdges.map(e => e.id),
      ]);

      return {
        nodes: state.nodes.filter(n => n.id !== nodeId),
        edges: [
          ...state.edges.filter(e => !edgeIdsToRemove.has(e.id)),
          ...newEdges,
        ],
        totalCount: Math.max(0, state.totalCount - 1),
        selectedNodeId: state.selectedNodeId === nodeId ? null : state.selectedNodeId,
      };
    }),
}));
