import { useCallback, useEffect, useMemo } from 'react';
import {
  ReactFlow,
  Background,
  Controls,
  MiniMap,
  useNodesState,
  useEdgesState,
  BackgroundVariant,
  ConnectionMode,
  type Node,
  type Edge,
  type NodeTypes,
  type EdgeTypes,
} from '@xyflow/react';
import { usePlanStore, type PlanNode } from '@/stores/plan-store';
import { useWebSocket } from '@/hooks/useWebSocket';
import { TaskNode } from './TaskNode';
import { DecisionNode } from './DecisionNode';
import { InsertableEdge } from './InsertableEdge';
import { useAutoLayout } from '@/hooks/useAutoLayout';
import { AnimatePresence } from 'framer-motion';

// Register custom node types - use any to bypass strict typing
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const nodeTypes: NodeTypes = {
  task: TaskNode,
  decision: DecisionNode,
} as any;

// Register custom edge types
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const edgeTypes: EdgeTypes = {
  insertable: InsertableEdge,
} as any;

export function PlanCanvas() {
  const { nodes: planNodes, edges: planEdges, setSelectedNodeId, plan, requestRerun, setPendingInsert } = usePlanStore();
  const { removeNode } = useWebSocket();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);

  // Auto-layout hook
  const { layoutNodes } = useAutoLayout();

  // Determine if plan is currently executing
  const isExecuting = plan?.status === 'executing';
  const isPaused = plan?.status === 'paused';
  const isCompleted = plan?.status === 'completed';
  // Can modify plan before execution starts (ready or approved status)
  const canModifyPlan = plan?.status === 'ready' || plan?.status === 'approved' || plan?.status === 'streaming';

  // Build set of completed/active node IDs for execution progress tracking
  const executedNodeIds = useMemo(() => {
    const ids = new Set<string>();
    planNodes.forEach(n => {
      if (n.status === 'completed' || n.status === 'active' || n.status === 'failed') {
        ids.add(n.id);
      }
    });
    return ids;
  }, [planNodes]);

  // Convert plan nodes to ReactFlow nodes
  useEffect(() => {
    // Build a map of decision node selections
    const branchSelections: Record<string, string | undefined> = {};
    planNodes.forEach((node: PlanNode) => {
      if (node.type === 'decision' && node.selectedBranchId) {
        branchSelections[node.id] = node.selectedBranchId;
      }
    });

    // Build maps for edge connections to detect branching/merging points
    const outgoingEdgesCount: Record<string, number> = {};
    const incomingEdgesCount: Record<string, number> = {};
    planEdges.forEach(edge => {
      outgoingEdgesCount[edge.from] = (outgoingEdgesCount[edge.from] || 0) + 1;
      incomingEdgesCount[edge.to] = (incomingEdgesCount[edge.to] || 0) + 1;
    });

    const rfNodes = planNodes.map((node: PlanNode) => {
      // Check if this node belongs to a branch that wasn't selected
      let isDisabledBranch = false;
      if (node.branchParent && node.branchId) {
        const selectedBranch = branchSelections[node.branchParent];
        if (selectedBranch && selectedBranch !== node.branchId) {
          isDisabledBranch = true;
        }
      }

      // During execution, unexecuted nodes should be dimmed
      const isUnexecuted = isExecuting && !executedNodeIds.has(node.id) && !isDisabledBranch;

      // Check if node can be modified based on edge connections
      // Can't insert after a node with multiple outgoing edges (branching point)
      // Can't remove a node with multiple incoming or outgoing edges
      const hasMultipleOutgoing = (outgoingEdgesCount[node.id] || 0) > 1;
      const hasMultipleIncoming = (incomingEdgesCount[node.id] || 0) > 1;
      const canInsertAfter = canModifyPlan && !hasMultipleOutgoing;
      const canRemove = canModifyPlan && !hasMultipleOutgoing && !hasMultipleIncoming;

      return {
        id: node.id,
        type: node.type,
        position: { x: 0, y: 0 },
        data: {
          ...node,
          isDisabledBranch,
          isUnexecuted,
          isExecuting: isExecuting || isPaused,
          isCompleted,
          canModify: canModifyPlan,
          canInsertAfter,
          canRemove,
          onRerunNode: requestRerun,
          onInsertNode: setPendingInsert,
          onRemoveNode: removeNode,
        },
      };
    });

    const rfEdges = planEdges.map((edge) => {
      const sourceNode = planNodes.find((n) => n.id === edge.from);
      const targetNode = planNodes.find((n) => n.id === edge.to);

      // Check if this edge connects to a disabled branch
      let isDisabledEdge = false;
      if (targetNode?.branchParent && targetNode?.branchId) {
        const selectedBranch = branchSelections[targetNode.branchParent];
        if (selectedBranch && selectedBranch !== targetNode.branchId) {
          isDisabledEdge = true;
        }
      }

      // Edge leading to active node should be animated/pulsing
      const isActiveEdge = targetNode?.status === 'active';

      // Edge is part of executed path
      const isExecutedEdge = sourceNode && executedNodeIds.has(sourceNode.id) &&
                             targetNode && (executedNodeIds.has(targetNode.id));

      // During execution, unexecuted edges should be dimmed
      const isUnexecutedEdge = isExecuting && !isExecutedEdge && !isDisabledEdge;

      // Determine edge color
      let strokeColor = '#3f3f46';
      if (isDisabledEdge) {
        strokeColor = '#27272a';
      } else if (isActiveEdge) {
        strokeColor = '#eab308'; // Yellow for active
      } else if (isExecutedEdge) {
        strokeColor = '#22c55e'; // Green for completed path
      } else if (isUnexecutedEdge) {
        strokeColor = '#27272a';
      }

      return {
        id: edge.id,
        source: edge.from,
        target: edge.to,
        type: 'insertable', // Use custom edge type
        animated: isActiveEdge,
        className: isActiveEdge ? 'edge-active-pulse' : '',
        data: {
          isActiveEdge,
          isExecutedEdge,
          isDisabledEdge,
          isUnexecutedEdge,
        },
        style: {
          stroke: strokeColor,
          strokeWidth: isActiveEdge ? 3 : 2,
          opacity: isDisabledEdge ? 0.3 : isUnexecutedEdge ? 0.4 : 1,
        },
      };
    });

    // Apply auto-layout
    const layoutedNodes = layoutNodes(rfNodes as unknown as Node[], rfEdges as unknown as Edge[]);
    setNodes(layoutedNodes as unknown as never[]);
    setEdges(rfEdges as unknown as never[]);
  }, [planNodes, planEdges, layoutNodes, setNodes, setEdges, isExecuting, isPaused, isCompleted, canModifyPlan, executedNodeIds, requestRerun, setPendingInsert, removeNode]);

  const onNodeClick = useCallback(
    (_: React.MouseEvent, node: Node) => {
      setSelectedNodeId(node.id);
    },
    [setSelectedNodeId]
  );

  const onPaneClick = useCallback(() => {
    setSelectedNodeId(null);
  }, [setSelectedNodeId]);

  return (
    <div className="w-full h-full">
      <AnimatePresence>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onNodeClick={onNodeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          edgeTypes={edgeTypes}
          connectionMode={ConnectionMode.Loose}
          fitView
          fitViewOptions={{
            padding: 0.2,
            maxZoom: 1.5,
          }}
          minZoom={0.1}
          maxZoom={2}
        >
          <Background
            variant={BackgroundVariant.Dots}
            gap={20}
            size={1}
            color="#27272a"
          />
          <Controls
            showInteractive={false}
            className="!bg-surface !border-border !rounded-lg"
          />
          <MiniMap
            nodeColor={(node) => {
              const data = node.data as unknown as PlanNode | undefined;
              const status = data?.status;
              switch (status) {
                case 'completed':
                  return '#22c55e';
                case 'active':
                  return '#eab308';
                case 'failed':
                  return '#ef4444';
                default:
                  return '#3f3f46';
              }
            }}
            maskColor="rgba(10, 10, 11, 0.8)"
            className="!bg-surface/80 !border-border !rounded-lg"
          />
        </ReactFlow>
      </AnimatePresence>

      {/* Empty state */}
      {!plan && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div className="text-center">
            <div className="w-16 h-16 mx-auto mb-4 rounded-2xl bg-surface/50 border border-border flex items-center justify-center">
              <svg
                className="w-8 h-8 text-text-muted"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={1.5}
                  d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2"
                />
              </svg>
            </div>
            <h3 className="text-lg font-medium text-text-primary mb-2">
              Waiting for plan...
            </h3>
            <p className="text-sm text-text-muted max-w-xs">
              Give your AI agent a task and watch the execution plan appear here in real-time.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}
